$headers = @{ 'Authorization' = "Bearer $env:NOTION_TOKEN"; 'Notion-Version' = '2022-06-28'; 'Content-Type' = 'application/json' }
$pageId = '3290a0b197cc801a8240e78d3bfe0e74'
$all = @()
$queue = @($pageId)
$seen = @{}
while ($queue.Count -gt 0) {
  $current = $queue[0]
  if ($queue.Count -eq 1) { $queue = @() } else { $queue = $queue[1..($queue.Count-1)] }
  if ($seen.ContainsKey($current)) { continue }
  $seen[$current] = $true
  $cursor = $null
  do {
    $uri = "https://api.notion.com/v1/blocks/$current/children?page_size=100"
    if ($cursor) { $uri += "&start_cursor=$cursor" }
    $resp = Invoke-RestMethod -Method Get -Uri $uri -Headers $headers
    foreach ($b in $resp.results) {
      $text = ''
      switch ($b.type) {
        'child_database' { $text = $b.child_database.title }
        'child_page' { $text = $b.child_page.title }
        'paragraph' { $text = ($b.paragraph.rich_text.plain_text -join '') }
        'heading_1' { $text = ($b.heading_1.rich_text.plain_text -join '') }
        'heading_2' { $text = ($b.heading_2.rich_text.plain_text -join '') }
        'heading_3' { $text = ($b.heading_3.rich_text.plain_text -join '') }
        'link_to_page' { $text = ($b.link_to_page.type + ':' + $b.link_to_page.database_id + $b.link_to_page.page_id) }
      }
      $all += [PSCustomObject]@{ parent = $current; id = $b.id; type = $b.type; has_children = $b.has_children; text = $text }
      if ($b.has_children) { $queue += $b.id }
    }
    $cursor = $resp.next_cursor
  } while ($resp.has_more)
}
$all | Where-Object { $_.type -in @('child_database','child_page','link_to_page','heading_1','heading_2','heading_3','paragraph') -and $_.text } | ConvertTo-Json -Depth 10

